/**
 * Accepts non-secret Phase 0 setup choices and validates selected provider metadata without running provider auth flows or persisting secrets. When classification_mode is omitted, the backend applies the selected provider recommendation before validation.
 * @summary Submit first-run setup choices
 */
export const setupSubmitSetupPost = async (
  setupSubmitRequest: SetupSubmitRequest,
  options?: RequestInit,
): Promise<setupSubmitSetupPostResponse> => {
  const res = await fetch(getSetupSubmitSetupPostUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(setupSubmitRequest),
  });

  const body = [204, 205, 304].includes(res.status) ? null : await res.text();

  const data: setupSubmitSetupPostResponse["data"] = body
    ? JSON.parse(body)
    : {};
  return {
    data,
    status: res.status,
    headers: res.headers,
  } as setupSubmitSetupPostResponse;
};

